INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (1,1,1,'Xóa sạch nợ – Nhẹ người bước sang giai đoạn mới','Mình sống trong trạng thái nhẹ đầu và không còn cảm giác bị đuổi theo bởi con số nợ.\r\nMình hình dung tài khoản gọn gàng, mỗi tháng trả nợ đều đặn, không né tránh sao kê.\r\nMình chủ động chia nhỏ khoản nợ, ưu tiên thứ tự trả, và kiên trì hoàn thành từng mốc một.','Không nợ nần – không ám ảnh – không trốn tránh',NULL,3060000.00,0.00,'円',NULL,0,'value','2026-01-01','2026-12-31',NULL,'high','in_progress',1,0,1,5,'2026-02-01 05:29:06','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (2,1,2,'42.195km – Chạy hết mình, về đích bình an','Tớ đứng ở vạch đích giải Tottori Marathon, mồ hôi ướt áo, chân mỏi rã nhưng tim bình thản.\r\nTrước mắt là biển Nhật Bản và gió lạnh mùa thu, xung quanh là tiếng cổ vũ nhỏ nhưng ấm.\r\nTớ đã chạy từng km một cách tỉnh táo, lắng nghe cơ thể, không bỏ cuộc, không vội vàng — và hoàn thành trọn vẹn 42.195km của chính mình.','Mỗi bước chân là một lời hứa với bản thân.','/storage/goals/dpeoTBoQ7iL1pAPu3j30asEov2tuYzfl4tIFfJI1.png',42.00,23.66,'km',NULL,56,'value','2026-01-01','2026-03-15',NULL,'high','in_progress',0,1,13,5,'2026-02-01 05:29:06','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (3,1,2,'Body Transformation','Pull up & Push up dễ dàng. Gym 3 buổi/tuần. Giảm body fat xuống 20%',NULL,NULL,20.00,25.40,'% body fat',25.40,0,'milestone','2026-01-01','2026-12-31','2026-02-01 12:37:55','high','in_progress',0,0,12,3,'2026-02-01 05:29:06','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (4,1,4,'Fundamental IT Engineer – Mốc nền tảng IT của mình','Mình đang ở trạng thái tự tin và vững nền tảng IT, không còn mơ hồ trước các khái niệm kỹ thuật.\r\nMình nhìn thấy bản thân ngồi học đều đặn, hiểu dần từng phần, làm mock test mà không còn sợ câu hỏi.\r\nMỗi tuần, mình học chậm nhưng chắc, ôn tập có hệ thống và từng bước tiến gần đến ngày thi FE.','Không cần giỏi ngay – chỉ cần đi đều.','/storage/goals/pDUBTWRMSyin3skzWSZqSNIYXA98LOalFdDvapah.webp',NULL,0.00,NULL,NULL,0,'milestone','2026-03-01','2026-06-01',NULL,'medium','not_started',0,1,14,5,'2026-02-01 05:29:06','2026-02-07 04:13:15');
