INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (6,1,6,'Project CSS 100 – Giữ chất lượng công việc ở mức xuất sắc','Mình làm việc trong trạng thái bình tĩnh, rõ ràng và có trách nhiệm, từng project được triển khai mạch lạc, giao tiếp dễ hiểu, không để khách phải đoán ý.\r\nMình thấy hình ảnh những email phản hồi tích cực, feedback gọn gàng, điểm CSS luôn ở mức cao và ổn định.\r\nMình chủ động chuẩn bị kỹ trước khi bắt đầu project, update tiến độ đều, xử lý vấn đề sớm và chốt project thật sạch, để mỗi lần khách đánh giá là một lần yên tâm.','Làm rõ ràng – Khách an tâm – Điểm số tự đến.','/storage/goals/YRp56gIy2I1sjXYeKyz2uwNYcDRQG3aJ8Rk3Md6M.jpg',100.00,0.00,'CSS points',NULL,0,'value','2026-01-01','2026-12-31',NULL,'low','paused',0,0,16,3,'2026-02-01 05:29:06','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (7,1,6,'Viết để sống, quay để giữ','Mình ở trong trạng thái sống chậm, tỉnh táo và thành thật với cảm xúc của chính mình.\r\nMình nhìn thấy những buổi tối yên, một góc bàn nhỏ, camera đặt im, từng dòng chữ được viết ra không để chứng minh mà để nhớ.\r\nMình duy trì mỗi tuần một bài blog — không cần hoàn hảo, chỉ cần có mặt. Song song đó, mình đều đặn đăng video YouTube để giữ lại những khoảnh khắc có thật: chậm, nhỏ, nhưng không bị bỏ quên.','Không cần hoàn hảo. Chỉ cần còn nhớ.','/storage/goals/HXWQou1RQ7P2XH7yEh04tRvq9QEhzCHr5OgGa9PQ.png',52.00,5.00,'blogs',NULL,10,'value','2026-01-01','2026-12-31',NULL,'high','in_progress',0,1,17,5,'2026-02-01 05:29:06','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (8,1,5,'Hong Kong – Winter Trip with Chu','Mình cảm thấy nhẹ nhõm, hào hứng và được sống chậm lại giữa nhịp đô thị quen mà lạ.\r\n\r\nHai đứa con gái đi bộ giữa những con phố đèn neon, gió lạnh tháng 12 lùa qua áo khoác. Buổi tối ngồi bên bến cảng Victoria Harbour, nhìn skyline sáng lên, cười nói rất khẽ.\r\n\r\nChu chủ động lên kế hoạch, mình thì tiết kiệm tiền, đặt vé – khách sạn, chuẩn bị lịch trình vừa đủ để đi, vừa đủ để nghỉ.','Hai đứa – một mùa đông – một thành phố','/storage/goals/cjoIYfDTBIl9hHWOm9EBQ2eLvuKD3oP8soxseSIy.png',NULL,0.00,NULL,NULL,0,'value','2026-03-01','2026-12-31',NULL,'low','not_started',0,0,18,3,'2026-02-01 05:29:06','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (9,1,4,'12 cuốn sách – 12 điểm dừng cho tâm trí','Ở trạng thái bình tĩnh và hiện diện, mình thường xuyên nhìn thấy hình ảnh bản thân ngồi đọc sách trong ánh đèn vàng buổi tối, hoặc bên cửa sổ ngày mưa, điện thoại để xa.\r\nMỗi tháng, mình chủ động chọn 1 cuốn sách, đọc chậm, có ghi chú, và cho phép bản thân đọc vì thích chứ không vì áp lực hoàn thành.','Mỗi tháng một cuốn – đủ chậm để thấm, đủ đều để đi xa.','/storage/goals/HPxu6kBBV7OVgwkXYGFCXDx0mpZktcw0Dk3UW8tC.jpg',12.00,0.00,'冊',NULL,0,'value','2026-01-01','2026-12-31',NULL,'medium','paused',0,0,19,3,'2026-02-01 06:16:55','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (10,1,5,'Lên đỉnh đều đặn, không áp lực tiền','Mình ở trong trạng thái cơ thể khỏe, tinh thần nhẹ. Mỗi tháng, mình xỏ giày leo núi, hít thở không khí rừng, bước từng bước vững vàng lên đỉnh. Mình chọn những chuyến đi vừa sức, vừa túi tiền, để thiên nhiên trở thành một phần nhịp sống chứ không phải một “xa xỉ phẩm”.','Ít nhưng đều – gần mà sâu','/storage/goals/y8tDIyrCDmy2XxZrPjgjKUbXXUePl0GbJ2Yn1aI3.jpg',12.00,2.00,'山頂',0.00,17,'value','2026-01-01','2026-12-31',NULL,'medium','paused',0,0,11,3,'2026-02-01 20:24:48','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (11,1,1,'Học đầu tư chứng khoán cơ bản cùng HIEU TV','Mình ở trạng thái bình tĩnh và chủ động với tiền bạc.\r\nMình hình dung bản thân hiểu rõ cách thị trường vận hành, biết nên làm gì và tránh điều gì khi đầu tư.\r\nMình từng bước học hết khóa, ghi chú lại tư duy cốt lõi và thực hành đầu tư một cách kỷ luật, không vội vàng.','Hiểu trước – vào tiền sau',NULL,5.00,0.00,'Module',NULL,0,'value','2026-01-01','2026-12-31',NULL,'high','in_progress',1,0,3,3,'2026-02-02 21:19:19','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (12,1,4,'14 Day Smartphone Filmmaker – Làm phim bằng điện thoại một cách chuyên nghiệp','Mình tự tin quay – dựng – kể chuyện bằng chính chiếc điện thoại của mình.\r\nMỗi ngày, mình học một kỹ năng cụ thể và thực hành ngay bằng video ngắn, ánh sáng đời thường, câu chuyện thật.\r\nSau 14 ngày, mình có tư duy làm phim rõ ràng, workflow gọn gàng và đủ nền tảng để làm YouTube, social content hoặc dự án cá nhân.','One day. One skill. One real video.',NULL,14.00,0.00,'日',NULL,0,'value','2026-03-01','2026-03-14',NULL,'medium','not_started',0,0,4,3,'2026-02-02 21:19:39','2026-02-07 04:13:15');
