INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (14,1,6,'Vẽ đều đặn – giữ nhịp sáng tạo mỗi tuần','Mình ở trong trạng thái bình tĩnh và tập trung, ngồi một mình bên bàn vẽ nhỏ, ánh đèn vàng chiếu xuống giấy.\r\n\r\nMỗi tuần, mình dành ra một khoảng thời gian cố định để vẽ một bức tranh hoàn chỉnh, không áp lực đẹp – xấu, chỉ cần thành thật với cảm xúc của mình ở thời điểm đó.','Không cần giỏi hơn ai, chỉ cần đều với chính mình.',NULL,52.00,1.00,'枚',NULL,2,'value','2026-01-01','2026-12-31',NULL,'high','in_progress',1,0,0,3,'2026-02-02 21:20:58','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (15,1,4,'English for Travel – Speak with Ease','Mình giao tiếp bằng tiếng Anh một cách tự nhiên khi đi du lịch: tự tin hỏi đường, check-in khách sạn, gọi món, trò chuyện ngắn với người lạ mà không sợ sai.\r\nMình hình dung bản thân đứng ở sân bay, quán café, ga tàu – nói tiếng Anh chậm rãi, rõ ràng, đủ dùng và thoải mái.\r\nMình luyện nói tiếng Anh đều đặn mỗi ngày qua các tình huống du lịch thực tế, ưu tiên nói được hơn là nói hoàn hảo.','Enough English to go anywhere',NULL,NULL,0.00,NULL,NULL,0,'value','2026-06-01','2026-12-31',NULL,'low','not_started',0,0,10,3,'2026-02-02 21:24:05','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (16,1,3,'Kết nối đều đặn – yêu thương không gián đoạn','Mình ở xa nhưng không xa lòng. Mình hình dung những cuộc gọi nhẹ nhàng, nghe giọng nhau sau một ngày dài, chia sẻ những điều nhỏ nhặt và cảm giác được thuộc về. Mình chủ động giữ kết nối bằng cách gọi điện, hỏi han, lắng nghe – không vì nghĩa vụ, mà vì yêu thương.','Xa nhau về địa lý, gần nhau về tinh thần.',NULL,NULL,0.00,NULL,NULL,0,'milestone','2026-01-01','2026-12-31',NULL,'low','not_started',0,0,5,3,'2026-02-04 03:59:10','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (17,1,3,'Món quà mang cảm giác “được thấu hiểu”','Mình ở trong trạng thái bình thản và ấm áp, hình dung người thương mỉm cười khi mở món quà sinh nhật. Mình dành thời gian quan sát, lắng nghe và chuẩn bị từng chi tiết nhỏ, để món quà không chỉ là vật chất mà là cảm giác được quan tâm và trân trọng.','Không cần đắt tiền, chỉ cần đúng tim.',NULL,NULL,0.00,NULL,NULL,0,'value','2026-01-01','2026-12-31',NULL,'medium','not_started',0,0,6,3,'2026-02-04 03:59:38','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (18,1,8,'gia nhập lại 日本ユニセフ協会',NULL,NULL,NULL,NULL,0.00,NULL,NULL,0,'milestone','2026-01-01','2026-12-31',NULL,'low','not_started',0,0,7,3,'2026-02-04 04:06:19','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (19,1,7,'Sống cùng thiên nhiên một cách có ý thức','Mình ở trong trạng thái nhẹ và mở. Mình cảm nhận gió, ánh sáng, mặt đất và nhịp thở của thiên nhiên quanh mình. Mình chủ động bước ra ngoài – đi bộ, leo núi, ra biển hoặc chỉ đứng yên nhìn trời – như một cách kết nối và nạp lại năng lượng tinh thần.','Thiên nhiên là nơi mình trở về',NULL,72.00,0.00,'回',NULL,0,'value','2026-01-01','2026-12-31',NULL,'medium','not_started',0,0,8,3,'2026-02-04 04:12:31','2026-02-07 04:13:15');
INSERT INTO `goals` (`id`, `user_id`, `category_id`, `title`, `description`, `slogan`, `cover_image`, `target_value`, `current_value`, `unit`, `start_value`, `progress`, `progress_mode`, `start_date`, `target_date`, `completed_at`, `priority`, `status`, `is_pinned`, `is_core_goal`, `sort_order`, `orbit_scale`, `created_at`, `updated_at`) VALUES (20,1,5,'Công tác Fukuoka – Làm việc tập trung, sống gọn gàng','Mình ở trong trạng thái làm việc tập trung nhưng cơ thể vẫn nhẹ và tinh thần thoải mái. \r\n\r\nMình hình dung những buổi sáng chạy bộ ở Fukuoka, hít thở không khí trong lành trước giờ làm. \r\nSau giờ làm, mình đi ăn những món đặc sản địa phương, cảm nhận thành phố bằng nhịp sống chậm. \r\nCuối tuần, mình leo núi nhẹ hoặc đi solo trip, vừa khám phá vừa nạp lại năng lượng. \r\n\r\nMình làm việc trọn vẹn trong tuần và cho bản thân không gian sống đúng nghĩa.','Làm việc trọn vẹn, sống không vội.',NULL,NULL,0.00,NULL,NULL,0,'milestone','2026-02-09','2026-02-28',NULL,'medium','not_started',1,0,2,3,'2026-02-04 19:27:01','2026-02-07 04:13:15');
