INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (36,9,'BOOK REVIEW TEMPLATE','đọc xong là viết được ngay, không áp lực “review hay”','- VI version\r\n    \r\n    ## 1. Thông tin sách\r\n    \r\n    - **Tên sách:**\r\n    - **Tác giả:**\r\n    - **Thể loại:**\r\n    - **Thời điểm đọc:**\r\n    - **Hoàn cảnh đọc:**\r\n    \r\n    ---\r\n    \r\n    ## 2. Cảm giác còn lại sau khi gấp sách\r\n    \r\n    > (1–3 câu, chỉ nói cảm giác, không phân tích)\r\n    > \r\n    \r\n    ---\r\n    \r\n    ## 3. Cuốn sách này nói về điều gì?\r\n    \r\n    > (mô tả ngắn gọn, tránh tóm tắt dài)\r\n    > \r\n    \r\n    **Công thức gợi ý:**\r\n    \r\n    > Đây là cuốn sách về …, xoay quanh …, dưới góc nhìn …\r\n    > \r\n    \r\n    ---\r\n    \r\n    ## 4. Những đoạn / ý làm mình dừng lại\r\n    \r\n    - \r\n    - \r\n    - \r\n    \r\n    *(trích nguyên văn hoặc diễn giải lại)*\r\n    \r\n    ---\r\n    \r\n    ## 5. Cuốn sách chạm vào mình ở đâu?\r\n    \r\n    > (trả lời ít nhất 1 ý)\r\n    > \r\n    - Nó chạm vào một suy nghĩ cũ / nỗi lo / giai đoạn nào của mình?\r\n    - Nó xác nhận hay làm mình nghi ngờ điều gì?\r\n    \r\n    ---\r\n    \r\n    ## 6. Sau khi đọc, mình thay đổi điều gì?\r\n    \r\n    > (rất nhỏ cũng được)\r\n    > \r\n    - Một suy nghĩ mới:\r\n    - Một hành động / thái độ:\r\n    \r\n    ---\r\n    \r\n    ## 7. Cuốn sách này dành cho ai?\r\n    \r\n    - Phù hợp với:\r\n    - Có thể chưa phù hợp nếu:\r\n    \r\n    ---\r\n    \r\n    ## 8. Đánh giá cá nhân\r\n    \r\n    - ⭐⭐⭐⭐☆\r\n    - Có / không đọc lại\r\n    - Có / không giới thiệu\r\n    \r\n    ---\r\n    \r\n    ## 9. Một câu để khép lại\r\n    \r\n    > (1 câu duy nhất – như đặt cuốn sách trở lại kệ)\r\n    > \r\n    \r\n    ---\r\n    \r\n    ### 🔖 Ghi chú thêm (tuỳ chọn)\r\n    \r\n    - Từ khóa của cuốn sách:\r\n    - Nếu đọc lại, mình muốn đọc chậm ở chương:\r\n    \r\n    ---\r\n    \r\n    ## 📌 Cách dùng template này cho mượt (gợi ý nhỏ)\r\n    \r\n    - Không cần viết đủ 100% mỗi lần\r\n    - **Bắt buộc có:** mục 2 – 5 – 9\r\n    - Mỗi review coi như **1 cuộc trò chuyện đã kết thúc**, không cần “hay”',NULL,12.00,'2026-12-31',NULL,0,5,1,'2026-02-02 18:44:44','2026-02-03 06:31:56');
