INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (49,14,'Thử nghiệm & mở rộng','Bắt đầu thử chất liệu, màu sắc hoặc cách vẽ mới nhưng vẫn giữ nhịp 1 tranh / tuần.','- Thử nhưng không ép\n- Có thể quay lại cách cũ bất cứ lúc nào',NULL,39.00,'2026-09-30',NULL,0,4,0,'2026-02-03 22:45:21','2026-02-03 22:45:21');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (50,14,'Hoàn thành một năm vẽ đều','Khép lại năm 2026 với 52 bức tranh – một hành trình vẽ đều và trung thực với chính mình.','- Không cần tổng kết quá nhiều\n- Chỉ cần nhìn lại',NULL,52.00,'2026-12-31',NULL,0,5,0,'2026-02-03 22:46:14','2026-02-03 22:46:14');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (51,15,'Làm quen & phản xạ với tiếng Anh du lịch cơ bản','Nắm được các mẫu câu thiết yếu và bắt đầu phản xạ nói không ngại sai','Tập trung: sân bay – khách sạn – quán ăn\r\nKhông học ngữ pháp sâu',NULL,NULL,NULL,NULL,0,1,0,'2026-02-03 23:25:18','2026-02-04 21:50:39');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (52,19,'Làm quen với việc kết nối thiên nhiên hàng tuần','Tạo thói quen ra ngoài và ở cùng thiên nhiên một cách có ý thức.','Không cần đi xa. Công viên, con đường yên tĩnh, bờ sông hay bãi biển gần nhà đều được. Chỉ cần có mặt trọn vẹn, không vội vàng, không multitask.',NULL,12.00,'2026-03-31',NULL,0,1,0,'2026-02-04 04:13:27','2026-02-04 16:20:40');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (53,19,'Mở rộng thời gian và không gian ở cùng thiên nhiên','Kết nối thiên nhiên với sự quan sát sâu hơn.','Chú ý ánh sáng, gió, âm thanh xung quanh và cảm giác cơ thể khi di chuyển. Không nghe nhạc, không podcast.',NULL,18.00,'2026-06-30',NULL,0,2,0,'2026-02-04 04:13:35','2026-02-04 16:21:35');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (54,19,'Ghi nhận cảm xúc sau mỗi lần kết nối thiên nhiên','Kết hợp thiên nhiên với việc ghi nhận nội tâm.','Có thể viết vài dòng, ghi chú nhanh hoặc chụp một tấm ảnh làm dấu mốc. Không cần phân tích hay đánh giá.',NULL,18.00,'2026-09-30',NULL,0,3,0,'2026-02-04 04:13:43','2026-02-04 16:22:18');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (55,19,'Quay lại những nơi thiên nhiên quen thuộc','Xây dựng mối liên kết dài hạn với một vài không gian thiên nhiên.','Quan sát sự thay đổi của cảnh vật theo mùa và cảm nhận sự thay đổi bên trong mình.',NULL,24.00,'2026-12-31',NULL,0,4,0,'2026-02-04 04:13:51','2026-02-04 16:23:27');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (56,12,'Day 1–2: Universal Camera Settings','Hiểu và làm chủ camera setting trên smartphone','Exposure, FPS, Resolution, White Balance – áp dụng trên chính điện thoại đang dùng',NULL,2.00,'2026-03-02',NULL,0,1,0,'2026-02-04 16:41:38','2026-02-06 05:48:20');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (57,12,'Day 3–4: Gear & Composition','Biết dùng gear tối giản + bố cục hình ảnh có chủ ý','Tripod, mic, ánh sáng cơ bản + rule of thirds, leading lines',NULL,2.00,'2026-03-04',NULL,0,2,0,'2026-02-04 16:42:19','2026-02-06 05:48:29');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (58,12,'Day 5–7: Movement, Lighting & Audio','Tạo cảm giác cinematic bằng chuyển động, ánh sáng và âm thanh','Pan, tilt, handheld; ánh sáng tự nhiên; thu audio sạch',NULL,3.00,'2026-03-07',NULL,0,3,0,'2026-02-04 16:43:00','2026-02-06 05:48:39');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (59,12,'Day 8–11: Storytelling & Editing','Kể chuyện bằng hình ảnh và dựng video mạch lạc','Story arc, nhịp dựng, intro – outro, workflow edit',NULL,4.00,'2026-03-11',NULL,0,4,0,'2026-02-04 16:43:38','2026-02-06 05:48:48');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (60,12,'Day 12–14: Publishing & Commercial Thinking','Ứng dụng video cho YouTube, social và commercial','Audience, format, branding, tư duy làm việc chuyên nghiệp',NULL,3.00,'2026-03-14',NULL,0,5,0,'2026-02-04 16:44:22','2026-02-06 05:48:56');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (63,1,'Khởi động lại – trả nợ thẻ đều 3 tháng','Xây nhịp trả nợ ổn định, không đứt gãy','Quan trọng hơn số tiền là: mình không trốn tránh nữa.',NULL,150000.00,'2026-04-30',NULL,0,1,0,'2026-02-04 16:56:01','2026-02-04 17:41:41');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (64,1,'Cán mốc 30万円 nợ Credit Card','Nhìn thấy nợ giảm rõ ràng lần đầu.','Mình không nhanh, nhưng mình không đứng yên.',NULL,300000.00,'2026-06-30',NULL,0,2,0,'2026-02-04 16:58:13','2026-02-04 16:58:13');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (65,1,'Dùng bonus tháng 7 để đẩy mạnh trả nợ thẻ','Tận dụng tiền bonus để giảm mạnh nợ có lãi.','Bonus không phải để tiêu cho quên mệt, mà để nhẹ đầu hơn.',NULL,450000.00,'2026-07-10',NULL,0,3,0,'2026-02-04 16:58:45','2026-02-04 17:42:48');
