INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (73,6,'Đạt CSS ≥ 90 ở đánh giá giữa năm','Khách hài lòng về cả kết quả và cách làm việc','- Chủ động báo rủi ro sớm\n- Update đều, không để khách phải hỏi',NULL,90.00,'2026-06-30',NULL,0,2,0,'2026-02-04 19:20:56','2026-02-04 19:20:56');
