INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (76,20,'Week 0 – Chuẩn bị tại Osaka','Ổn định nhịp sống, hoàn tất mọi chuẩn bị trước khi đi công tác.','Không mang việc lặt vặt sang Fukuoka.',NULL,NULL,'2026-02-08',NULL,0,1,0,'2026-02-04 19:50:49','2026-02-04 22:25:59');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (77,20,'Week 1 – Khởi động tại Fukuoka','Làm quen môi trường, vào nhịp làm việc.','Lịch công tác ổn định + bắt đầu chạy bộ',NULL,NULL,'2026-02-15',NULL,0,2,0,'2026-02-04 19:52:01','2026-02-04 20:00:04');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (78,20,'Week 2 – Triển khai chính','Xử lý phần việc quan trọng nhất của chuyến công tác. Hoàn thiện các phần còn lại, xử lý phát sinh.','Cân bằng giữa công việc và sống. 90% công việc + 1 chuyến leo núi / solo trip',NULL,NULL,'2026-02-22',NULL,0,3,0,'2026-02-04 19:55:14','2026-02-04 20:01:07');
