INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (83,16,'Thiết lập nhịp gọi ổn định','Bắt đầu gọi điện đều đặn, không để việc liên lạc bị đứt quãng vì bận rộn.','Mình ưu tiên sự hiện diện hơn độ dài cuộc gọi. 5–10 phút cũng được, miễn là đều.',NULL,NULL,'2026-03-31',NULL,0,1,0,'2026-02-04 21:18:24','2026-02-04 21:18:24');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (84,16,'Tạo cảm giác kết nối tự nhiên','Cuộc gọi trở nên thoải mái hơn, không còn cảm giác nghĩa vụ hay phải “báo cáo”.','Mình cho phép cuộc trò chuyện xoay quanh những điều rất nhỏ: ăn gì, mệt không, hôm nay trời thế nào.',NULL,NULL,'2026-06-30',NULL,0,2,0,'2026-02-04 21:19:16','2026-02-04 21:19:16');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (85,16,'Kết nối cảm xúc sâu hơn','Không chỉ hỏi thăm, mà có sự chia sẻ về cảm xúc, suy nghĩ và đời sống tinh thần.','Mình cho phép bản thân nói ra cả những lúc mệt, nhớ nhà, hoặc cần được động viên.',NULL,NULL,'2026-09-30',NULL,0,3,0,'2026-02-04 21:20:24','2026-02-04 21:20:24');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (86,16,'Giữ kết nối như một phần đời sống','Gọi điện không còn là mục tiêu cần hoàn thành, mà là thói quen tự nhiên trong cuộc sống xa nhà.','Mình không đo lường bằng số lượng nữa, mà bằng cảm giác: sau mỗi cuộc gọi, mình thấy yên tâm hơn.',NULL,NULL,'2026-12-31',NULL,0,4,0,'2026-02-04 21:21:32','2026-02-04 21:21:32');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (87,17,'Lập danh sách người thương & ngày sinh nhật','Tổng hợp đầy đủ bạn bè và gia đình quan trọng cùng ngày sinh nhật của họ.','Phân nhóm:\n- Gia đình\n- Bạn thân\n- Bạn thân vừa / đồng nghiệp thân\n\nGhi chú thêm:\n- Mối quan hệ\n- Khoảng cách hiện tại (gần / xa)',NULL,NULL,'2026-03-31',NULL,0,1,0,'2026-02-04 21:25:05','2026-02-04 21:25:05');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (88,17,'Bổ sung hồ sơ cá nhân từng người','Ghi lại sở thích, tính cách và gợi ý quà phù hợp cho mỗi người.','Với mỗi người, ghi nhanh:\n- Sở thích nổi bật (ăn uống, đồ dùng, tinh thần)\n- Vibe quà hợp: Thiết thực, Cảm xúc, Trải nghiệm\n- Ngân sách phù hợp',NULL,NULL,'2026-04-15',NULL,0,2,0,'2026-02-04 21:26:03','2026-02-04 21:26:03');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (89,17,'Sắp xếp lịch sinh nhật theo tháng','Nhóm sinh nhật theo từng tháng để dễ chuẩn bị trước.','Mỗi tháng list:\n- Tên\n- Ngày sinh\n- Mức độ ưu tiên\nĐánh dấu:\n🎂 Sinh nhật trùng tháng nhiều\n⭐ Người cần chuẩn bị kỹ',NULL,NULL,'2026-04-30',NULL,0,3,0,'2026-02-04 21:26:45','2026-02-04 21:26:45');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (90,17,'Xác định chiến lược quà theo nhóm','Đặt nguyên tắc chung để không bị quá tải hoặc áp lực tài chính.','- Gia đình: quà + lời chúc kỹ\n- Bạn thân: quà cá nhân hoá + lời chúc + thiệp\n- Bạn bè: quà nhỏ / nhắn tin / ăn cùng\n- Xa nhau: ship + message',NULL,NULL,'2026-04-30',NULL,0,4,0,'2026-02-04 21:28:28','2026-02-04 21:28:28');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (91,17,'Chuẩn bị quà sinh nhật trong năm',NULL,'- Chuẩn bị trước ≥ 2 tuần\r\n- Không mua sát ngày\r\n- Có lời chúc tử tế\r\n\r\nBảng LISTUP\r\n- Tên\r\n- Nhóm (Gia đình / Bạn thân / Bạn bè)\r\n- Ngày sinh\r\n- Sở thích chính\r\n- Gợi ý quà\r\n- Ngân sách\r\n- Ghi chú cảm xúc',NULL,NULL,'2026-06-25',NULL,0,5,0,'2026-02-04 21:29:41','2026-02-04 21:30:39');
INSERT INTO `milestones` (`id`, `goal_id`, `title`, `description`, `memo`, `image_path`, `target_value`, `due_date`, `completed_at`, `is_completed`, `sort_order`, `is_soft`, `created_at`, `updated_at`) VALUES (92,11,'Hoàn thành Module 1 – Vì sao phải đầu tư','Xây dựng mindset và lý do đầu tư đúng đắn','- 3 bài\n- Tập trung vào tư duy dài hạn, không kiếm tiền nhanh\n- Hiểu “vì sao đầu tư” trước khi học kỹ thuật',NULL,NULL,NULL,NULL,0,1,0,'2026-02-04 21:43:51','2026-02-04 21:43:51');
