INSERT INTO `goal_references` (`id`, `goal_id`, `type`, `title`, `content`, `file_path`, `file_name`, `file_size`, `sort_order`, `created_at`, `updated_at`) VALUES (2,20,'text','🌙 MINI ROUTINE – 1 THÁNG CÔNG TÁC','## 🌅 BUỔI SÁNG – “đặt nhịp cho ngày”\r\n\r\n⏰ không cần sớm, chỉ cần **đều**\r\n\r\n**Mỗi sáng**\r\n\r\n- Uống nước → mở rèm → hít thở 3 nhịp\r\n- Pha **cafe quen vị** (đồ m mang theo á)\r\n- Viết **1 dòng** vào sổ\r\n    \r\n    → *hôm nay muốn nhẹ ở chỗ nào*\r\n    \r\n\r\n**2–3 ngày / tuần**\r\n\r\n- 🏃‍♀️ Chạy nhẹ 20–40 phút\r\n    \r\n    → về nhà giãn cơ + protein\r\n    \r\n    → cảm giác: *mình đang chăm sóc cơ thể, không chỉ đi làm*\r\n    \r\n\r\n---\r\n\r\n## ☀️ SAU GIỜ LÀM – “không về nhà là nằm”\r\n\r\n(chỗ dễ trống trải nhất)\r\n\r\n**Ngày thường**\r\n\r\n- Chọn **1 hành động nhỏ** trước khi về nhà:\r\n    - đi bộ thêm 10 phút\r\n    - ghé 1 quán cafe yên\r\n    - hoặc mua trái cây về nhà\r\n\r\n👉 không cần mỗi ngày, **2–3 lần / tuần là đủ**\r\n\r\n**Về nhà**\r\n\r\n- Tắm nước ấm\r\n- Mặc đồ thoải mái\r\n- Ăn đơn giản (đừng skip bữa)\r\n\r\n---\r\n\r\n## 🌿 BUỔI TỐI – “giữ mình ở lại với chính mình”\r\n\r\n**Mỗi tối**\r\n\r\n- Không mở mạng xã hội ít nhất **30 phút đầu**\r\n- Chọn **1 trong 3**:\r\n    - 📖 đọc 5–10 trang sách\r\n    - 🎨 vẽ nguệch ngoạc (không cần đẹp)\r\n    - ✍️ viết vài dòng kiểu “hôm nay mình ổn/chưa ổn ở đâu”\r\n\r\n**Trước ngủ**\r\n\r\n- Chuẩn bị đồ cho sáng hôm sau\r\n- Ghi **1 điều nhỏ trong ngày** (kể cả rất bình thường)\r\n\r\n---\r\n\r\n## 🏞️ CUỐI TUẦN – “mỗi tuần 1 điểm tựa”\r\n\r\n👉 đừng để cuối tuần trôi mất\r\n\r\n**Mỗi tuần chọn 1**\r\n\r\n- 🌳 thiên nhiên: công viên / biển / leo núi nhẹ\r\n- ☕ cafe xa một chút\r\n- 🎒 day trip nhỏ (Dazaifu / Itoshima)\r\n\r\n**Ritual cố định**\r\n\r\n- Sáng: cafe + sổ\r\n- Trưa: ăn món mình thích\r\n- Chiều: đi bộ không mục đích\r\n- Tối: ăn nhẹ, về sớm\r\n\r\n---',NULL,NULL,NULL,2,'2026-02-05 03:01:34','2026-02-05 03:01:34');
INSERT INTO `goal_references` (`id`, `goal_id`, `type`, `title`, `content`, `file_path`, `file_name`, `file_size`, `sort_order`, `created_at`, `updated_at`) VALUES (3,20,'file','名称未設定-1.jpg',NULL,'references/20/UcT8TYV7IIxkZvg1GNUDWWwUIEg5uAW0NyylKfZg.jpg','名称未設定-1.jpg',43137,3,'2026-02-05 03:20:58','2026-02-05 03:20:58');
INSERT INTO `goal_references` (`id`, `goal_id`, `type`, `title`, `content`, `file_path`, `file_name`, `file_size`, `sort_order`, `created_at`, `updated_at`) VALUES (4,10,'text','Checklist đi mùa đông','### Đồ bắt buộc mang (đi tuyết)\r\n\r\n* 🥾 Giày trekking \r\n* 🧊 Crampon\r\n* 🧤 Găng tay 2 cái\r\n* 🧣 Mũ len / khăn cổ\r\n* 🧥 Áo phao + áo gió ngoài\r\n* 🧦 Tất dày\r\n* 🎒 Ba lô\r\n\r\n---\r\n\r\n### Đồ nên mang thêm\r\n\r\n* ☕ Bình nước giữ nhiệt (trà nóng / nước ấm)\r\n* 🍫 Snack năng lượng (socola, bánh protein, mì, trứng)\r\n* 🔋 Pin sạc dự phòng \r\n* 🕶️ Kính râm\r\n* Camera\r\n\r\n---\r\n\r\n### 5️⃣ Lưu ý sống còn ⚠️\r\n\r\n* ❄️ Cắt móng chân\r\n* Sạc pin dự phòng và pin cam, điện thoại, đồng hồ\r\n* Download map ngoại tuyến\r\n* Mang tiền mặt ~￥2,000',NULL,NULL,NULL,1,'2026-02-06 04:38:29','2026-02-06 05:46:48');
